// CHECK-NEXT:    store i32 [[TMP6]], ptr [[DST]], align 4, !tbaa [[TBAA6]]
// CHECK-NEXT:    [[TMP7:%.*]] = tail call i32 @llvm.riscv.esp.movi.8.a.m(<16 x i8> [[SHUFFLE]], i32 7)
