// CHECK-NEXT:    store i32 [[TMP7]], ptr [[ARRAYIDX7]], align 4, !tbaa [[TBAA6]]
// CHECK-NEXT:    [[TMP8:%.*]] = bitcast <16 x i8> [[SHUFFLE]] to <8 x i16>
// CHECK-NEXT:    [[TMP9:%.*]] = tail call i32 @llvm.riscv.esp.movi.16.a.m(<8 x i16> [[TMP8]], i32 0)
